import xml.etree.ElementTree as ET
from xml.parsers.expat import ExpatError
import io

def validate_xml_document(xml_content):
    """
    Validates an XML document and prevents XXE attacks.
    
    Args:
        xml_content (str or bytes): The XML content to validate
        
    Returns:
        tuple: (is_valid, error_message)
    """
    try:
        # Parse the XML content
        parser = ET.XMLParser()
        # Disable external entity processing
        parser.entity = None
        parser.setFeature(ET.XML_FEATURE_EXTERNAL_GENERAL_ENTITIES, False)
        parser.setFeature(ET.XML_FEATURE_EXTERNAL_PARAMETER_ENTITIES, False)
        parser.setFeature(ET.XML_FEATURE_LOAD_EXTERNAL_DTD, False)
        
        # Parse the XML
        if isinstance(xml_content, str):
            xml_content = xml_content.encode('utf-8')
        
        root = ET.fromstring(xml_content, parser=parser)
        
        # Basic validation - check if root element exists
        if root is None:
            return False, "Invalid XML: No root element found"
            
        return True, "XML is valid"
        
    except ET.ParseError as e:
        return False, f"XML Parse Error: {str(e)}"
    except ExpatError as e:
        return False, f"XML Expat Error: {str(e)}"
    except Exception as e:
        return False, f"Unexpected error: {str(e)}"

def safe_xml_load(file_path):
    """
    Safely loads and validates an XML file from disk.
    
    Args:
        file_path (str): Path to the XML file
        
    Returns:
        tuple: (is_valid, error_message, root_element)
    """
    try:
        # Create parser with security settings
        parser = ET.XMLParser()
        parser.setFeature(ET.XML_FEATURE_EXTERNAL_GENERAL_ENTITIES, False)
        parser.setFeature(ET.XML_FEATURE_EXTERNAL_PARAMETER_ENTITIES, False)
        parser.setFeature(ET.XML_FEATURE_LOAD_EXTERNAL_DTD, False)
        
        # Parse the file
        tree = ET.parse(file_path, parser=parser)
        root = tree.getroot()
        
        return True, "XML file loaded successfully", root
        
    except ET.ParseError as e:
        return False, f"XML Parse Error: {str(e)}", None
    except Exception as e:
        return False, f"Error loading file: {str(e)}", None